options.script:
var suites = {};
var scenarioMap = {};

data.series.forEach(function(frame) {
  var valueField = null;
  var suite_id = null;
  var scenario_id = null;
  var frameName = frame.name || '';

  frame.fields.forEach(function(field) {
    if (field.labels) {
      if (field.labels.suite_id) suite_id = field.labels.suite_id;
      if (field.labels.scenario_id) scenario_id = field.labels.scenario_id;
      // frame name이 비어있으면 field name에서 메트릭 추출
      if (!frameName && field.name) frameName = field.name;
    }
    if (field.type === 'number' && field.values && field.values.length > 0) {
      valueField = field.values[field.values.length - 1];
    }
  });

  if (!suite_id || !scenario_id || valueField == null) return;

  var key = suite_id + '|' + scenario_id;
  suites[suite_id] = true;
  if (!scenarioMap[key]) {
    scenarioMap[key] = { suite_id: suite_id, scenario_id: scenario_id };
  }

  // 메트릭 이름으로 구분, 안되면 값 범위로 구분 (0~1이면 성공률)
  var isSuccessRate = frameName.indexOf('success_rate') !== -1;
  var isRunsTotal = frameName.indexOf('runs_total') !== -1;
  if (!isSuccessRate && !isRunsTotal) {
    // fallback: 값이 0~1 사이면 성공률, 아니면 실행횟수
    isSuccessRate = (valueField >= 0 && valueField <= 1);
    isRunsTotal = !isSuccessRate;
  }

  if (isSuccessRate) {
    scenarioMap[key].success_rate = valueField;
  } else if (frameName.indexOf('last_status') !== -1) {
    // fail_reason 라벨 추출
    frame.fields.forEach(function(f) {
      if (f.labels && f.labels.fail_reason) {
        scenarioMap[key].fail_reason = f.labels.fail_reason;
      }
    });
  } else {
    scenarioMap[key].runs = valueField;
  }
});

var labels = [];
var parents = [];
var values = [];
var markerColors = [];
var texts = [];
var customdata = [];

Object.keys(suites).forEach(function(suite) {
  // suite 성공률 평균 계산
  var total = 0, count = 0;
  Object.keys(scenarioMap).forEach(function(k) {
    var sc = scenarioMap[k];
    if (sc.suite_id === suite && sc.success_rate != null) {
      total += sc.success_rate; count++;
    }
  });
  var avgSr = count > 0 ? total / count : -1;
  var suiteColor;
  if (avgSr < 0) { suiteColor = '#4a4a6a'; }
  else if (avgSr < 0.5) { suiteColor = '#8B1A2A'; }
  else if (avgSr < 0.7) { suiteColor = '#8B5500'; }
  else { suiteColor = '#1a5c2a'; }
  labels.push(suite);
  parents.push('');
  values.push(0);
  markerColors.push(suiteColor);
  var srText = avgSr >= 0 ? (avgSr * 100).toFixed(0) + '%' : 'N/A';
  texts.push('📦 ' + suite + '<br>평균 성공률: ' + srText);
  customdata.push('suite');
});

Object.keys(scenarioMap).forEach(function(key) {
  var sc = scenarioMap[key];
  var runs = sc.runs || 1;
  var sr = sc.success_rate != null ? sc.success_rate : -1;
  var color;
  if (sr < 0) { color = '#555577'; }
  else if (sr < 0.5) { color = '#F2495C'; }
  else if (sr < 0.7) { color = '#FF9830'; }
  else { color = '#73BF69'; }
  labels.push(sc.scenario_id);
  parents.push(sc.suite_id);
  values.push(runs);
  markerColors.push(color);
  var srText = sr >= 0 ? (sr * 100).toFixed(0) + '%' : 'N/A';
  var failText = (sr >= 0 && sr < 1 && sc.fail_reason) ? '<br>❌ ' + sc.fail_reason : '';
  texts.push(sc.scenario_id + '<br>실행: ' + runs + '회<br>성공률: ' + srText + failText);
  customdata.push('scenario');
});

return {
  data: [{
    type: 'treemap',
    labels: labels,
    parents: parents,
    values: values,
    marker: {
      colors: markerColors,
      pad: { t: 30, l: 4, r: 4, b: 4 },
      line: { width: 2, color: '#1a1a2e' }
    },
    text: texts,
    customdata: customdata,
    hovertemplate: '%{text}<extra></extra>',
    textinfo: 'label',
    textfont: { size: 12, color: '#ffffff' },
    branchvalues: 'remainder',
    pathbar: { visible: false }
  }],
  layout: {
    paper_bgcolor: 'rgba(0,0,0,0)',
    plot_bgcolor: 'rgba(0,0,0,0)',
    font: { color: '#ffffff', size: 12, family: 'Arial' },
    margin: { t: 10, b: 10, l: 10, r: 10 }
  },
  config: { responsive: true }
};
